'use client';

import type { LessonRecurrence, ScheduledLessonDto } from '@soenglish/shared-types';
import { AchievementCard, Button, EmptyStateCard, Field, SurfaceCard } from '../../../components/ui';
import type { MockStudent } from '../../../mocks';
import styles from './page.module.scss';

export function StudentProfileTab({
  student,
  onChange,
  canEdit,
  viewerRole,
  onSave,
}: {
  student: MockStudent;
  onChange: (next: MockStudent) => void;
  canEdit: boolean;
  viewerRole: 'student' | 'teacher' | 'admin' | 'super-admin';
  onSave: () => void;
}) {
  const isStudentViewer = viewerRole === 'student';
  const isTeacherViewer = viewerRole === 'teacher';
  return (
    <SurfaceCard className={styles.tabCard}>
      <div className={styles.formGrid}>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Full name</label>
          <Field className={styles.input} value={student.fullName} disabled={!canEdit} onChange={(e) => onChange({ ...student, fullName: e.target.value })} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Email</label>
          <Field className={styles.input} value={student.email} disabled={!canEdit} onChange={(e) => onChange({ ...student, email: e.target.value })} />
        </div>
        {!isStudentViewer ? (
          <div className={styles.fieldGroup}>
            <label className={styles.label}>Level</label>
            <Field as="select" className={styles.input} value={student.level} disabled={!canEdit} onChange={(e) => onChange({ ...student, level: e.target.value })}>
              {['A1', 'A2', 'B1', 'B2', 'C1', 'C2'].map((level) => (
                <option key={level} value={level}>
                  {level}
                </option>
              ))}
            </Field>
          </div>
        ) : null}
        {!isTeacherViewer ? (
          <div className={styles.fieldGroup}>
            <label className={styles.label}>Phone</label>
            <Field className={styles.input} value={student.phone} disabled={!canEdit} onChange={(e) => onChange({ ...student, phone: e.target.value })} />
          </div>
        ) : null}
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Timezone</label>
          <Field as="select" className={styles.input} value={student.timezone} disabled={!canEdit} onChange={(e) => onChange({ ...student, timezone: e.target.value })}>
            {['Europe/Kyiv', 'Europe/Warsaw', 'Europe/London', 'America/New_York'].map((timezone) => (
              <option key={timezone} value={timezone}>
                {timezone}
              </option>
            ))}
          </Field>
        </div>
        {!isStudentViewer ? (
          <div className={styles.fieldGroup}>
            <label className={styles.label}>Status</label>
            <Field as="select" className={styles.input} value={student.status} disabled={!canEdit} onChange={(e) => onChange({ ...student, status: e.target.value as 'active' | 'paused' })}>
              <option value="active">active</option>
              <option value="paused">paused</option>
            </Field>
          </div>
        ) : null}
        {!isStudentViewer ? (
          <div className={styles.fieldGroup}>
            <label className={styles.label}>Schedule type</label>
            <Field
              as="select"
              className={styles.input}
              value={student.scheduleType}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...student, scheduleType: e.target.value as 'fixed' | 'flexible' })}
            >
              <option value="fixed">fixed</option>
              <option value="flexible">flexible</option>
            </Field>
          </div>
        ) : null}
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Calendar color (HEX)</label>
          <Field
            type="text"
            className={styles.input}
            value={student.calendarColor ?? ''}
            disabled={!canEdit}
            placeholder="#3b82c4"
            onChange={(e) => onChange({ ...student, calendarColor: e.target.value })}
          />
        </div>
      </div>
      <div className={styles.fieldGroup}>
        <label className={styles.label}>Notes</label>
        <Field as="textarea" className={`${styles.input} ${styles.notes}`} value={student.notes} disabled={!canEdit} onChange={(e) => onChange({ ...student, notes: e.target.value })} rows={4} />
      </div>
      <div className={styles.actions}>
        <Button type="button" className={styles.primaryBtn} disabled={!canEdit} onClick={onSave}>
          Save student data
        </Button>
      </div>
    </SurfaceCard>
  );
}

export function StudentCalendarTab({ lessons }: { lessons: ScheduledLessonDto[] }) {
  if (!lessons.length) {
    return <EmptyStateCard title="No lessons yet" description="Plan a lesson in the Schedule tab." />;
  }

  return (
    <div className={styles.calendarList}>
      {lessons.map((lesson) => (
        <SurfaceCard key={lesson.id} className={styles.calendarItem}>
          <div className={styles.calendarTitle}>{lesson.title}</div>
          <div className={styles.calendarMeta}>
            {lesson.date} · {lesson.startTime} · {lesson.teacherName}
          </div>
        </SurfaceCard>
      ))}
    </div>
  );
}

export function StudentScheduleTab({
  canEdit,
  lessonType,
  setLessonType,
  date,
  setDate,
  time,
  setTime,
  recurrence,
  setRecurrence,
  comment,
  setComment,
  onPlan,
}: {
  canEdit: boolean;
  lessonType: string;
  setLessonType: (v: string) => void;
  date: string;
  setDate: (v: string) => void;
  time: string;
  setTime: (v: string) => void;
  recurrence: LessonRecurrence;
  setRecurrence: (v: LessonRecurrence) => void;
  comment: string;
  setComment: (v: string) => void;
  onPlan: () => void;
}) {
  return (
    <SurfaceCard className={styles.tabCard}>
      <div className={styles.formGrid}>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Lesson type</label>
          <Field as="select" className={styles.input} value={lessonType} disabled={!canEdit} onChange={(e) => setLessonType(e.target.value)}>
            <option value="grammar">Grammar</option>
            <option value="vocabulary">Vocabulary</option>
            <option value="speaking">Speaking</option>
            <option value="listening">Listening</option>
          </Field>
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Date</label>
          <Field type="date" className={styles.input} value={date} disabled={!canEdit} onChange={(e) => setDate(e.target.value)} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Time</label>
          <Field type="time" className={styles.input} value={time} disabled={!canEdit} onChange={(e) => setTime(e.target.value)} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Recurrence</label>
          <Field as="select" className={styles.input} value={recurrence} disabled={!canEdit} onChange={(e) => setRecurrence(e.target.value as LessonRecurrence)}>
            <option value="none">No repeat</option>
            <option value="weekly">Weekly</option>
            <option value="monthly">Monthly</option>
          </Field>
        </div>
      </div>
      <div className={styles.fieldGroup}>
        <label className={styles.label}>Comment</label>
        <Field as="textarea" className={`${styles.input} ${styles.notes}`} value={comment} disabled={!canEdit} onChange={(e) => setComment(e.target.value)} rows={3} />
      </div>
      <div className={styles.actions}>
        <Button type="button" className={styles.primaryBtn} disabled={!canEdit || !date || !time} onClick={onPlan}>
          Plan lesson
        </Button>
      </div>
    </SurfaceCard>
  );
}

export function StudentAchievementsTab({
  achievements,
}: {
  achievements: Array<{ icon: React.ReactNode; label: string; description?: string; unlocked: boolean }>;
}) {
  return (
    <SurfaceCard className={styles.tabCard}>
      <div className={styles.achievementsGrid}>
        {achievements.map((achievement) => (
          <AchievementCard
            key={achievement.label}
            icon={achievement.icon}
            label={achievement.label}
            description={achievement.description}
            unlocked={achievement.unlocked}
            className={styles.achievement}
            unlockedClassName={styles.achievementUnlocked}
            lockedClassName={styles.achievementLocked}
            iconClassName={styles.achievementIcon}
            labelClassName={styles.achievementLabel}
          />
        ))}
      </div>
    </SurfaceCard>
  );
}
